mapper.sql:
WHERE b.status = 1 AND b.entid = #{entid}
AND b.date >= #{start} AND b.date <= #{end}

	AND CAST(b.uid AS UNSIGNED) IN
	#{u}


	AND c.contract_category IN
	#{cat}

mapper.select:
SELECT COUNT(1) FROM eb_customer t
WHERE t.deleted_at IS NULL
AND t.created_at >= #{start} AND t.created_at <= #{end}

	AND t.uid IN
	#{u}

SELECT COUNT(1) FROM eb_contract t
WHERE t.deleted_at IS NULL
AND t.start_date IS NOT NULL
AND t.start_date >= #{start} AND t.start_date <= #{end}

	AND t.uid IN
	#{u}


	AND t.id IN
	#{cid}

SELECT IFNULL(SUM(t.contract_price), 0) FROM eb_contract t
WHERE t.deleted_at IS NULL
AND t.start_date IS NOT NULL
AND t.start_date >= #{start} AND t.start_date <= #{end}

	AND t.uid IN
	#{u}


	AND t.id IN
	#{cid}

SELECT IFNULL(SUM(t.surplus), 0) FROM eb_contract t WHERE t.deleted_at IS NULL AND (t.signing_status IS NULL OR t.signing_status = '' OR CAST(t.signing_status AS UNSIGNED) < 2)
AND t.uid IN #{u}
AND t.id IN #{cid}

SELECT DATE_FORMAT(b.date, ${dateFormat}) AS name, CAST(IFNULL(SUM(b.num), 0) * 100 AS SIGNED) AS cnt
AND b.types IN #{tp}
GROUP BY DATE_FORMAT(b.date, ${dateFormat}) ORDER BY name ASC
